235→    fun suspendCard() {
236→        launchCatchingIO {
237→            val cardId = currentCard.await().id
238→            undoableOp {
239→                sched.suspendCards(ids = listOf(cardId))
240→            }.count
241→            actionFeedbackFlow.emit(CollectionManager.TR.studyingCardSuspended())
