245→
246→    fun suspendNote() {
247→        launchCatchingIO {
248→            val noteId = currentCard.await().nid
249→            undoableOp {
250→                sched.suspendNotes(ids = listOf(noteId))
251→            }
252→            actionFeedbackFlow.emit(CollectionManager.TR.studyingNoteSuspended())
253→            updateCurrentCard()
