190→    private fun setBackSideOnlyButtonIcon(menu: Menu, isBackSideOnly: Boolean) {
191→        menu.findItem(R.id.action_back_side_only).apply {
192→            if (isBackSideOnly) {
193→                setIcon(R.drawable.ic_card_answer)
194→                setTitle(R.string.card_side_answer)
195→            } else {
196→                setIcon(R.drawable.ic_card_question)
197→                setTitle(R.string.card_side_both)
198→            }
199→        }
200→    }
201→
202→    private val editCardLauncher = registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
203→        viewModel.handleEditCardResult(result)
204→    }
205→
206→    private fun editCard() {
207→        val intent = viewModel.getNoteEditorDestination().toIntent(requireContext())
208→        editCardLauncher.launch(intent)
209→    }
210→
211→    override fun dispatchKeyEvent(event: KeyEvent): Boolean {
212→        if (event.action != KeyEvent.ACTION_DOWN) return false
213→
214→        when (event.keyCode) {
215→            KeyEvent.KEYCODE_DPAD_LEFT -> {
216→                requireView().findViewById<MaterialButton>(R.id.show_previous).performClickIfEnabled()
217→            }
218→            KeyEvent.KEYCODE_DPAD_RIGHT -> {
219→                requireView().findViewById<MaterialButton>(R.id.show_next).performClickIfEnabled()
220→            }
221→            KeyEvent.KEYCODE_R -> viewModel.replayAudios()
222→            else -> return false
223→        }
224→        return true
225→    }
