227→    companion object {
228→        /** Index of the card to be first displayed among the IDs provided by [CARD_IDS_FILE_ARG] */
229→        const val CURRENT_INDEX_ARG = "currentIndex"
230→
231→        /** Argument key to a [PreviewerIdsFile] with the IDs of the cards to be displayed */
232→        const val CARD_IDS_FILE_ARG = "cardIdsFile"
233→
234→        fun getIntent(context: Context, previewerIdsFile: PreviewerIdsFile, currentIndex: Int): Intent {
235→            val arguments = bundleOf(
236→                CURRENT_INDEX_ARG to currentIndex,
237→                CARD_IDS_FILE_ARG to previewerIdsFile
238→            )
239→            return PreviewerActivity.getIntent(context, PreviewerFragment::class, arguments)
240→        }
241→    }
242→}
