250→        /** Complete rendering by applying any pending custom filters. */
251→        fun applyCustomFilters(
252→            rendered: TemplateReplacementList,
253→            ctx: TemplateRenderContext,
254→            frontSide: String?
255→        ): String {
256→            // template already fully rendered?
257→            if (len(rendered) == 1 && rendered[0].first != null) {
258→                return rendered[0].first!!
259→            }
260→
261→            var res = ""
262→            for (union in rendered) {
263→                if (union.first != null) {
264→                    res += union.first!!
265→                } else {
266→                    val node = union.second!!
267→                    // do we need to inject in FrontSide?
268→                    if (node.fieldName == "FrontSide" && frontSide != null) {
269→                        node.currentText = frontSide
270→                    }
271→
272→                    var fieldText = node.currentText
273→                    for (filterName in node.filters) {
274→                        fieldFilters[filterName]?.let {
275→                            fieldText = it.apply(fieldText, node.fieldName, filterName, ctx)
276→                        }
277→                    }
278→
279→                    res += fieldText
280→                }
281→            }
282→            return res
283→        }
284→    }
