286→    /**
287→     * Defines custom `{{filters:..}}`
288→     *
289→     * Custom filters can check `filterName` to decide whether it should modify
290→     * `fieldText` or not before returning it
291→     */
292→    abstract class FieldFilter {
293→        abstract fun apply(
294→            fieldText: String,
295→            fieldName: String,
296→            filterName: String,
297→            ctx: TemplateRenderContext
298→        ): String
299→    }
300→    companion object {
301→        val fieldFilters: MutableMap<String, FieldFilter> = mutableMapOf()
302→    }
