220→         * @param idx The index of the cloze to use
221→         * @return If the cloze strings are the same, return a single cloze string, otherwise, return
222→         * a string with a comma-separeted list of strings with the correct index.
223→         */
224→        @VisibleForTesting
225→        fun contentForCloze(txt: String, idx: Int): String? {
226→            // In Android, } should be escaped
227→            val re = Pattern.compile("\\{\\{c$idx::(.+?)\\}\\}")
228→            val m = re.matcher(txt)
229→            val matches: MutableList<String?> = ArrayList()
230→            var groupOne: String
231→            while (m.find()) {
232→                groupOne = m.group(1)!!
233→                val colonColonIndex = groupOne.indexOf("::")
234→                if (colonColonIndex > -1) {
235→                    // Cut out the hint.
236→                    groupOne = groupOne.substring(0, colonColonIndex)
237→                }
238→                matches.add(groupOne)
239→            }
240→            val uniqMatches: Set<String?> = HashSet(matches) // Allow to check whether there are distinct strings
241→
242→            // Make it consistent with the Desktop version (see issue #8229)
243→            return if (uniqMatches.size == 1) {
244→                matches[0]
245→            } else {
246→                matches.joinToString(", ")
247→            }
248→        }
249→    }
