  7→     filter: invert(100%);
  8→}
  9→
 10→video {
 11→    max-width: 100%;
 12→}
 13→
 14→body.night_mode {
 15→  color: white;
 16→  background-color: black;
 17→}
 18→
 19→body.ankidroid_dark_mode {
 20→  background-color: #303030;
 21→}
 22→
 23→#content {
 24→  margin: 0.5em;
 25→}
 26→
 27→/* For the typed/correct answer comparison. The typePrompt and typeOff
 28→  classes are AnkiDroid specific, and used only for older (before
 29→  4.0) Android versions . typePrompt is a placeholder where the input
 30→  box should be. typeOff is added when the user switched off entering
 31→  the answer. */
 32→.typeGood {
 33→  background-color: #0f0;
 34→}
 35→
 36→.typeBad {
 37→  background-color: #f00;
 38→}
 39→
 40→.typeMissed {
 41→  background-color: #ccc;
 42→}
 43→
 44→@font-face {
 45→    font-family: "Free Mono";
 46→    src: url("file:///android_asset/fonts/freefont/FreeMono.ttf")
 47→}
 48→
 49→#typeans {
 50→  width: 100%;
 51→  font-family: "Free Mono";
 52→}
 53→
 54→.typePrompt {
 55→  color: magenta;
 56→}
 57→
 58→.typePrompt.typeOff {
 59→  display: none;
 60→}
 61→
 62→.night_mode input#typeans {
 63→  color: white;
 64→  background-color: black;
 65→}
 66→
 67→.night_mode .typeGood {
 68→  background-color: #508040;
 69→}
 70→
 71→.night_mode .typeBad {
 72→  background-color: #905050;
 73→}
 74→
 75→.ankidroid_dark_mode input#typeans {
 76→  background-color: #303030;
 77→}
 78→
 79→.replay-button {
 80→  text-decoration: none;
 81→}
 82→
 83→/*
 84→Use hard-coded max dimensions if using Chrome back-end. Chrome is able to
 85→zoom into images correctly even with max dimensions specified, so this way is
 86→preferred over using JavaScript.
 87→*/
 88→.chrome img {
 89→  max-width: 100%;
 90→  max-height: 90%;
 91→}
 92→
 93→.vertically_centered {
 94→  position: absolute;
 95→  width: 100%;
 96→  height: 100%;
 97→  display: -webkit-box;
 98→  -webkit-box-align: stretch;
 99→  -webkit-box-pack: center;
100→  -webkit-box-orient: vertical;
101→}
102→
103→
104→/* Make sure the replay buttons look black or white unless explicitly
105→changed. Use some fancy CSS to make the button align vertically, and
106→scale up, but not down.  */
107→
108→.replay-button span {
109→  display: inline-block;
110→  vertical-align: middle;
111→  padding: 5px;
112→}
113→
114→.replay-button span svg {
115→  stroke: none;
116→  fill: black;
117→  display: inline;
118→  height: 1em;
119→  width: 1em;
120→  min-width: 32px;
121→  min-height: 32px;
122→}
123→
124→.replay-button span img {
125→  display: inline;
126→  height: 1em;
127→  width: 1em;
128→  min-width: 32px;
129→  min-height: 32px;
130→}
131→.night_mode .replay-button svg {
132→  fill: white;
133→}
