     */
    @Test
    fun `parseSourcesToFileScheme - preserves cloze spans with images`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"

        @Language("HTML")
        val content = """Name: <span class="cloze">[...]</span><br>Pic: <img src="face.jpg">"""

