@VisibleForTesting
fun parseSourcesToFileScheme(content: String, mediaDir: String): String {
    // Use parseBodyFragment instead of parse to better handle HTML fragments
    // This preserves the content structure without wrapping it in a full HTML document
    // which could modify the HTML in unexpected ways
    // See: https://github.com/ankidroid/Anki-Android/issues/15951
    val doc = Jsoup.parseBodyFragment(content)
    doc.outputSettings(OutputSettings().prettyPrint(false))"}

