    /**
     * Executes a user-defined JavaScript action.
     *
     * This allows users to trigger JavaScript functions defined in card templates.
     * Card templates can define a variable like `var userJs1 = revealNext;` and this
     * function will call it when the corresponding user action is triggered via
     * gestures, keyboard shortcuts, or gamepad buttons.
     *
     * Similar to AnkiMobile's User Action 1-8 feature.
     * @see <a href="https://docs.ankimobile.net/study-tools.html">AnkiMobile User Actions</a>
     *
     * @param actionNumber The user action number (1-9)
     */
    private fun executeUserAction(actionNumber: Int) {
        // Call the userJsX function if it exists and is callable
        // This follows the AnkiMobile convention where users define:
        // var userJs1 = someFunction;
        loadUrlInViewer("javascript: if (typeof userJs$actionNumber === 'function') { userJs$actionNumber(); } else if (typeof userJs$actionNumber !== 'undefined') { userJs$actionNumber; }")
    }"}

