        /**
         * Migrates bindings from removed commands to their equivalent commands:
         * - FLIP_OR_ANSWER_RECOMMENDED -> FLIP_OR_ANSWER_EASE3
         * - FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED -> FLIP_OR_ANSWER_EASE4
         */
        internal class UpgradeAnswerRecommendedBindings : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                migrateBindings(
                    preferences,
                    oldKey = "binding_FLIP_OR_ANSWER_RECOMMENDED",
                    newCommand = ViewerCommand.FLIP_OR_ANSWER_EASE3
                )
                migrateBindings(
                    preferences,
                    oldKey = "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED",
                    newCommand = ViewerCommand.FLIP_OR_ANSWER_EASE4
                )
            }

            private fun migrateBindings(
                preferences: SharedPreferences,
                oldKey: String,
                newCommand: ViewerCommand
            ) {
                val oldValue = preferences.getString(oldKey, null) ?: return
                if (oldValue.isBlank()) {
                    preferences.edit { remove(oldKey) }
                    return
                }

                // Parse old bindings and add them to the new command
                val bindings = MappableBinding.fromPreferenceString(oldKey)
                for (binding in bindings) {
                    newCommand.addBindingAtEnd(preferences, binding)
                }

                preferences.edit { remove(oldKey) }
            }
        }
    }
